// src/app/core/utils/schedule.utils.ts
function cronToHuman(schedule) {
  const parts = schedule.cron.trim().split(/\s+/);
  if (parts.length !== 5)
    return schedule.cron;
  const [minute, hour, dayOfMonth, , dayOfWeek] = parts;
  const tz = schedule.timezone ?? "UTC";
  const cityLabel = tz.includes("/") ? tz.split("/").pop()?.replaceAll("_", " ") : tz;
  const time = `${hour.padStart(2, "0")}:${minute.padStart(2, "0")}`;
  if (dayOfMonth !== "*") {
    return `Monthly on day ${dayOfMonth} at ${time} ${cityLabel}`;
  }
  const dayNames = [
    "Sunday",
    "Monday",
    "Tuesday",
    "Wednesday",
    "Thursday",
    "Friday",
    "Saturday"
  ];
  if (dayOfWeek !== "*") {
    const dayIndex = Number.parseInt(dayOfWeek, 10);
    const dayName = !Number.isNaN(dayIndex) && dayIndex >= 0 && dayIndex <= 6 ? dayNames[dayIndex] : dayOfWeek;
    return `Every ${dayName} at ${time} ${cityLabel}`;
  }
  return `Daily at ${time} ${cityLabel}`;
}
function getReportTypeLabel(reportType, reportTypes) {
  return reportTypes.find((r) => r.report_type === reportType)?.display_name ?? reportType;
}

